/**
 * Generated by `createservice miniapp.GetOIDCClientService '--type=queries'`
 */

const { throwAuthenticationError } = require('@open-condo/keystone/apolloErrorFormatter')
const { GQLCustomSchema, getByCondition, find } = require('@open-condo/keystone/schema')

const { REMOTE_SYSTEM } = require('@dev-portal-api/domains/common/constants/common')
const { productionClient, developmentClient } = require('@dev-portal-api/domains/common/utils/serverClients')
const { CondoB2BAppGql, CondoB2CAppGql, CondoOIDCClientGql } = require('@dev-portal-api/domains/condo/gql')
const access = require('@dev-portal-api/domains/miniapp/access/GetOIDCClientService')
const { PROD_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const { formatOIDCClient } = require('@dev-portal-api/domains/miniapp/utils/serverSchema/oidcClient')

function getOIDCClientWhere (app) {
    return {
        importId: app.id,
        importRemoteSystem: REMOTE_SYSTEM,
    }
}


const GetOIDCClientService = new GQLCustomSchema('GetOIDCClientService', {
    types: [
        {
            access: true,
            type: 'input AppWhereUniqueInput { id: ID! }',
        },
        {
            access: true,
            type: 'input GetOIDCClientInput { app: AppWhereUniqueInput!, environment: AppEnvironment! }',
        },
        {
            access: true,
            type: 'input GetAllOIDCClientsInput { environment: AppEnvironment! }',
        },
        {
            access: true,
            type: 'type OIDCClient { id: String!, clientId: String!, name: String, redirectUri: String!, isEnabled: Boolean! }',
        },
    ],
    
    queries: [
        {
            access: access.canGetOIDCClient,
            schema: 'OIDCClient (data: GetOIDCClientInput!): OIDCClient',
            resolver: async (parent, args) => {
                const { data: { app, environment } } = args

                const serverClient = environment === PROD_ENVIRONMENT
                    ? productionClient
                    : developmentClient

                const exportIdField = `${environment}ExportId`
                const oidcClientIdField = `${environment}OidcClientId`

                // Step 0: resolve local dev-portal app (B2B or B2C)
                const [b2bApp, b2cApp] = await Promise.all([
                    getByCondition('B2BApp', { id: app.id, deletedAt: null }),
                    getByCondition('B2CApp', { id: app.id, deletedAt: null }),
                ])
                const localApp = b2bApp || b2cApp
                const condoAppGql = b2bApp ? CondoB2BAppGql : CondoB2CAppGql

                // Step 1: try to find exported condoApp — if oidcClient is linked and not deleted, use it directly
                if (localApp) {
                    const condoApp = await serverClient.findExportedModel({
                        modelGql: condoAppGql,
                        exportId: localApp[exportIdField],
                        id: app.id,
                    })
                    if (condoApp && condoApp.oidcClient && !condoApp.oidcClient.deletedAt) {
                        return formatOIDCClient(condoApp.oidcClient)
                    }
                }

                // Steps 2+3 combined into a single request.
                // Two possible sources for the OIDC client:
                //   2. Explicit link: dev-portal app stores an `oidcClientId` (UUID) pointing directly to a condo OidcClient.
                //      This allows reusing a client that was created for a different app or outside the normal publish flow.
                //   3. Legacy/exported: the condo OidcClient was created via CreateOIDCClientService and carries
                //      importId=app.id + importRemoteSystem, matching by origin rather than explicit reference.
                // Both clauses are sent as OR to avoid two round-trips.
                const oidcClientId = localApp && localApp[oidcClientIdField]
                const orClauses = []
                if (oidcClientId) {
                    orClauses.push({ AND: [{ id: oidcClientId }] })
                }
                orClauses.push({ AND: [getOIDCClientWhere(app)] })

                const oidcClients = await serverClient.getModels({
                    modelGql: CondoOIDCClientGql,
                    where: { OR: orClauses },
                    first: 2,
                })

                if (!oidcClients.length) {
                    return null
                }

                // Prefer the client matched by explicit oidcClientId over the legacy importId match
                const preferred = oidcClientId && oidcClients.find(c => c.id === oidcClientId)
                return formatOIDCClient(preferred || oidcClients[0])
            },
        },
        {
            access: access.canGetAllOIDCClients,
            schema: 'allOIDCClients (data: GetAllOIDCClientsInput!): [OIDCClient!]',
            resolver: async (parent, args, context) => {
                // NOTE: Same logic as OIDCClient, but for all user-owned apps
                const { data: { environment } } = args
                const { authedItem: user } = context

                // NOTE: Checked in access, just a sanity check
                if (!user || !user.id) return throwAuthenticationError()

                const serverClient = environment === PROD_ENVIRONMENT
                    ? productionClient
                    : developmentClient

                const exportIdField = `${environment}ExportId`
                const oidcClientIdField = `${environment}OidcClientId`

                // Step 0: resolve local dev-portal apps (B2B or B2C), that are owned by the user
                const [b2bApps, b2cApps] = await Promise.all([
                    find('B2BApp', { createdBy: { id: user.id }, deletedAt: null }),
                    find('B2CApp', { createdBy: { id: user.id }, deletedAt: null }),
                ])

                // Map appId -> localApp for quick lookup during resolution
                const localAppById = Object.fromEntries(
                    [...b2bApps, ...b2cApps].map(app => [app.id, app])
                )

                // oidcClientsByAppId tracks the resolved OIDCClient per app (null = unresolved)
                const oidcClientsByAppId = Object.fromEntries(
                    Object.keys(localAppById).map(id => [id, null])
                )

                if (!Object.keys(oidcClientsByAppId).length) {
                    return []
                }

                // Step 1: fetch condoApps for all local apps in parallel, fill from condoApp.oidcClient
                // Match by exportId (precise) OR importId+remoteSystem (legacy), same as findExportedModel
                function buildCondoAppWhere (localApps) {
                    const exportIds = localApps.map(a => a[exportIdField]).filter(Boolean)
                    const appIds = localApps.map(a => a.id)
                    const clauses = []
                    if (exportIds.length) clauses.push({ AND: [{ id_in: exportIds }] })
                    clauses.push({ AND: [{ importRemoteSystem: REMOTE_SYSTEM, importId_in: appIds }] })
                    return { OR: clauses }
                }

                const [condoB2BApps, condoB2CApps] = await Promise.all([
                    b2bApps.length ? serverClient.getAllModels({ modelGql: CondoB2BAppGql, where: buildCondoAppWhere(b2bApps) }) : [],
                    b2cApps.length ? serverClient.getAllModels({ modelGql: CondoB2CAppGql, where: buildCondoAppWhere(b2cApps) }) : [],
                ])

                for (const condoApp of [...condoB2BApps, ...condoB2CApps]) {
                    if (!condoApp.oidcClient || condoApp.oidcClient.deletedAt) continue
                    // Match condoApp back to its local app via exportId or importId
                    const localApp = Object.values(localAppById).find(a =>
                        a[exportIdField] === condoApp.id || condoApp.importId === a.id
                    )
                    if (localApp) {
                        oidcClientsByAppId[localApp.id] = condoApp.oidcClient
                    }
                }

                // Steps 2+3: for apps still unresolved, batch-fetch OIDCClients by oidcClientId OR importId.
                // Same combined OR strategy as the single-app resolver — prefer oidcClientId match over importId.
                const unresolvedApps = Object.keys(oidcClientsByAppId)
                    .filter(id => oidcClientsByAppId[id] === null)
                    .map(id => localAppById[id])

                if (unresolvedApps.length) {
                    const oidcClientIds = unresolvedApps.map(a => a[oidcClientIdField]).filter(Boolean)
                    const appIds = unresolvedApps.map(a => a.id)

                    const orClauses = [
                        { AND: [{ importRemoteSystem: REMOTE_SYSTEM, importId_in: appIds }] },
                    ]
                    if (oidcClientIds.length) {
                        orClauses.push({ AND: [{ id_in: oidcClientIds }] })
                    }

                    const oidcClients = await serverClient.getAllModels({
                        modelGql: CondoOIDCClientGql,
                        where: { OR: orClauses },
                    })

                    // Index fetched clients for O(1) lookup
                    const clientById = Object.fromEntries(oidcClients.map(c => [c.id, c]))
                    const clientByImportId = Object.fromEntries(oidcClients.map(c => [c.importId, c]))

                    for (const app of unresolvedApps) {
                        const oidcClientId = app[oidcClientIdField]
                        // Prefer explicit oidcClientId match, fall back to importId (legacy)
                        const resolved = (oidcClientId && clientById[oidcClientId]) || clientByImportId[app.id]
                        if (resolved) {
                            oidcClientsByAppId[app.id] = resolved
                        }
                    }
                }

                return Object.values(oidcClientsByAppId).filter(Boolean).map(formatOIDCClient)
            },
        },
    ],
    
})

module.exports = {
    GetOIDCClientService,
    getOIDCClientWhere,
}
